#include <iostream>
#include <set>
#include <unordered_set>
#include <string>

int main() {
    std::cout << "=== std::set & std::unordered_set ===" << std::endl;

    // 1. std::set — sorted, unique elements
    std::cout << "\n--- std::set (sorted, unique) ---" << std::endl;
    std::set<int> numbers = {5, 2, 8, 2, 5, 1, 9, 3};

    std::cout << "Set contents (sorted, unique): ";
    for (int n : numbers) {
        std::cout << n << " ";
    }
    std::cout << std::endl;

    // 2. std::unordered_set — unordered, unique
    std::cout << "\n--- std::unordered_set (unordered, unique) ---" << std::endl;
    std::unordered_set<int> unorderedNums = {5, 2, 8, 2, 5, 1, 9, 3};

    std::cout << "Unordered set contents: ";
    for (int n : unorderedNums) {
        std::cout << n << " ";
    }
    std::cout << std::endl;

    // 3. Adding and removing
    std::cout << "\n--- Adding and removing ---" << std::endl;
    std::set<std::string> players = {"Hero", "Aragorn", "Gandalf"};

    players.insert("Legolas");  // Add
    players.insert("Hero");     // Duplicate — ignored!
    players.erase("Gandalf");   // Remove

    std::cout << "Players: ";
    for (const std::string& p : players) {
        std::cout << p << " ";
    }
    std::cout << std::endl;

    // 4. Checking membership
    std::cout << "\n--- Checking membership ---" << std::endl;
    std::set<int> unlockedLevels = {1, 2, 3, 5, 8};

    int level = 5;
    if (unlockedLevels.find(level) != unlockedLevels.end()) {
        std::cout << "Level " << level << " is unlocked!" << std::endl;
    } else {
        std::cout << "Level " << level << " is locked!" << std::endl;
    }

    // 5. Set operations
    std::cout << "\n--- Set operations ---" << std::endl;
    std::set<int> setA = {1, 2, 3, 4};
    std::set<int> setB = {3, 4, 5, 6};

    // Union
    std::set<int> unionSet;
    for (int n : setA) unionSet.insert(n);
    for (int n : setB) unionSet.insert(n);

    std::cout << "Union: ";
    for (int n : unionSet) std::cout << n << " ";
    std::cout << std::endl;

    // Intersection
    std::set<int> intersectSet;
    for (int n : setA) {
        if (setB.find(n) != setB.end()) {
            intersectSet.insert(n);
        }
    }

    std::cout << "Intersection: ";
    for (int n : intersectSet) std::cout << n << " ";
    std::cout << std::endl;

    // 6. Game use: unlocked achievements
    std::cout << "\n--- Unlocked Achievements (set) ---" << std::endl;
    std::set<std::string> achievements = {
        "First Kill",
        "Level 5",
        "Dragon Slayer",
        "Treasure Hunter"
    };

    std::cout << "Achievements unlocked: " << achievements.size() << std::endl;

    // Check specific achievement
    std::string check = "Dragon Slayer";
    if (achievements.find(check) != achievements.end()) {
        std::cout << "✅ " << check << " achieved!" << std::endl;
    }

    std::cout << "\n--- std::set vs std::unordered_set ---" << std::endl;
    std::cout << "std::set:" << std::endl;
    std::cout << "  • Sorted order" << std::endl;
    std::cout << "  • O(log n) operations" << std::endl;
    std::cout << "\nstd::unordered_set:" << std::endl;
    std::cout << "  • No order" << std::endl;
    std::cout << "  • O(1) average operations" << std::endl;

    return 0;
}

phase2.brokenCode:
#include <iostream>
#include <set>

int main() {
    std::set<int> numbers;

    // Trying to access by index (ERROR!)
    std::cout << numbers[0] << std::endl;

    return 0;
}

phase2.explanation:
`std::set` does NOT have `operator[]`! It's not a sequence container.

**The fix:**
```cpp
// Use iterators to access elements
auto it = numbers.begin();
if (it != numbers.end()) {
    std::cout << *it << std::endl;
}
```

**Or use range-based loops:**
```cpp
for (int n : numbers) {
    std::cout << n << " ";
}
```

**PlusPlus-chan says:**
"`std::set` is not an array. It's a tree. Use iterators or range-based loops."

phase3.solution:
#include <iostream>
#include <set>
#include <unordered_set>
#include <string>

int main() {
    std::set<int> unlockedLevels = {1, 2, 3, 5, 8};

    std::cout << "=== Unlocked Levels ===" << std::endl;
    for (int level : unlockedLevels) {
        std::cout << "Level " << level << std::endl;
    }

    unlockedLevels.insert(4);
    unlockedLevels.insert(3);  // Duplicate — ignored
    unlockedLevels.erase(8);

    if (unlockedLevels.find(5) != unlockedLevels.end()) {
        std::cout << "\n✅ Level 5 unlocked!" << std::endl;
    } else {
        std::cout << "\n❌ Level 5 locked!" << std::endl;
    }

    std::cout << "\nFinal Levels:" << std::endl;
    for (int level : unlockedLevels) {
        std::cout << "Level " << level << std::endl;
    }

    // Inventory
    std::unordered_set<std::string> inventory;
    inventory.insert("Sword");
    inventory.insert("Shield");
    inventory.insert("Potion");

    std::cout << "\n=== Inventory ===" << std::endl;
    if (inventory.find("Potion") != inventory.end()) {
        std::cout << "✅ Potion found in inventory!" << std::endl;
    }

    std::cout << "Items:" << std::endl;
    for (const std::string& item : inventory) {
        std::cout << "  - " << item << std::endl;
    }

    return 0;
}
